# OEIS sequence: A058005

from math import prod
from sympy.ntheory.factor_ import digits
from sympy import factorint
def A058005(n):
    f = factorint(2*n)
    def s(n,p): return sum(digits(n,p)[1:])
    return prod(p**min(f[p],((s(n,p)<<1)-s(n<<1,p))//(p-1)) for p in f) # _Chai Wah Wu_, May 05 2026

